let state={currentUser:null,route:'login',param:null,testMode:false,secretOpen:false,data:{states:{},observations:[],program:[],papas:[],notes:[],history:[],qualityNotes:[],restrictions:[],documents:[],techNotices:[]}};
let historyStack=[], forwardStack=[];
function load(){try{const s=JSON.parse(localStorage.getItem('checkobra_v11_base_real'));if(s)state={...state,...s,data:{...state.data,...(s.data||{})}}}catch{}}
function save(){localStorage.setItem('checkobra_v11_base_real',JSON.stringify(state));syncCloud();}
let syncing=false; async function syncCloud(){if(!cloudReady||syncing)return;try{await setDoc(doc(db,'checkobra','v11_base_real'),{...state.data,updatedAt:serverTimestamp()},{merge:true})}catch(e){console.warn('No se pudo guardar en nube',e)}}
function listenCloud(){if(!cloudReady)return;onSnapshot(doc(db,'checkobra','v11_base_real'),snap=>{if(!snap.exists())return;syncing=true;const d=snap.data();delete d.updatedAt;state.data={...state.data,...d};localStorage.setItem('checkobra_v11_base_real',JSON.stringify(state));syncing=false;render();});}
function u(){return users.find(x=>x.id===state.currentUser)}
function go(route,param=null){if(state.route!==route)historyStack.push({route:state.route,param:state.param});forwardStack=[];state.route=route;state.param=param;save();render();}
function back(){const x=historyStack.pop();if(!x)return;forwardStack.push({route:state.route,param:state.param});state.route=x.route;state.param=x.param;save();render();}
function forward(){const x=forwardStack.pop();if(!x)return;historyStack.push({route:state.route,param:state.param});state.route=x.route;state.param=x.param;save();render();}
function home(){go('home')}
function keyOf(dept,part,room='DEPTO'){return `${dept}|${part}|${room}`}
function getState(dept,part,room='DEPTO'){return state.data.states[keyOf(dept,part,room)]||{status:'Sin iniciar',avance:0,dept,part,room,by:'',date:''}}

function depsMissing(dept,part){const req=dependencies[part]||[];return req.filter(dep=>{const st=getState(dept,dep,'DEPTO').status;return !['Ejecutada','Validada Calidad'].includes(st);});}
function canOverrideBlock(){return ['gonzalo','paul','vicente','cristobal'].includes(u().id);}
function setPartStatus(dept,part,room,status,av=0,obs=''){const cur=getState(dept,part,room);state.data.states[keyOf(dept,part,room)]={...cur,status,avance:Number(av),dept,part,room,by:u().name,date:new Date().toLocaleString(),obs};state.data.history.unshift({id:Date.now(),type:'estado',text:`${u().name} cambió ${part} Depto ${dept} ${room==='DEPTO'?'':room} a ${status}`,date:new Date().toLocaleString()});if(status==='Ejecutada'){state.data.qualityNotes.unshift({id:Date.now(),from:u().name,dept,part,room,status:'Pendiente validación',date:new Date().toLocaleString()});}save();}
function deptMeta(dept){const f=Math.floor(dept/100), col=dept%100, type=typeByCol[col]||'A';return {floor:f,col,type,area:areaByType[type],rooms:typeRooms[type]||[]}}
function partApplies(part,rooms){if(deptLevelParts.includes(part))return ['DEPTO'];if(part==='Cerámicos Muro')return rooms.filter(r=>/baño|cocina/i.test(r));if(part==='Impermeabilización Baños'||part==='Vigones')return rooms.filter(r=>/baño/i.test(r));if(part==='Tabiquería')return rooms.filter(r=>!/terraza/i.test(r));if(part==='Cerámicos Piso')return rooms;return rooms;}
function userParts(user=u()){return user.profile==='supervisor'?user.works:allParts}
function statusRank(s){return {'Sin iniciar':0,'En ejecución':1,'Ejecutada':2,'Validada Calidad':3,'Observada':-1}[s]??0}
function deptProgressFor(dept,parts=userParts()){const {rooms}=deptMeta(dept);let total=0, score=0, observed=false, exec=false;parts.forEach(p=>partApplies(p,rooms).forEach(r=>{total++;const st=getState(dept,p,r).status;if(st==='Observada')observed=true;if(st==='En ejecución'||st==='Ejecutada')exec=true;if(st==='Validada Calidad')score++;}));const pct=total?Math.round(score/total*100):0;let cls='gray',txt='Sin iniciar';if(observed){cls='red';txt='Observado'}else if(pct===100){cls='green';txt='Completado'}else if(exec||pct>0){cls='yellow';txt='En ejecución'}return {pct,cls,txt,total,score};}
function floorProgress(f,parts=userParts()){let max=f===2?5:6, sum=0;for(let c=1;c<=max;c++)sum+=deptProgressFor(f*100+c,parts).pct;return Math.round(sum/max)}
function observationsForUser(user=u()){return state.data.observations.filter(o=>o.resp===user.id&&o.status!=='Cerrada')}
function pendingProgramFor(user=u()){return state.data.program.filter(p=>p.resp===user.id&&!['Cumplido','Cancelado'].includes(p.status))}
function papasFor(user=u()){return state.data.papas.filter(p=>(p.to===user.id||p.to==='todos')&&p.status!=='Cerrada')}
function canManage(){return canAssign.includes(u().id)}
function canPapa(){return canCreatePapa.includes(u().id)}
function appShell(content){const user=u();const paulPanel=(user.id==='paul'&&state.secretOpen)?`<div class="secretPanel"><b>Panel Paul</b><button class="secondary" onclick="toggleTestMode()">${state.testMode?'Activar claves':'Desactivar claves'}</button><select id="quickUser"><option value="">Cambiar usuario</option>${users.map(x=>`<option value="${x.id}">${x.name} · ${x.role}</option>`).join('')}</select><button class="secondary" onclick="quickSwitchUser()">Entrar al perfil</button></div>`:'';return `<header class="header"><img class="logo" src="assets/logo-aitue.png" onclick="secretTap()"><div><h1>CheckObra</h1><p>${user.name} · ${user.role}</p></div><button class="logout" onclick="logout()">Salir</button></header><main class="screen">${content}${paulPanel}</main>${state.route==='login'?'':`<nav class="bottomNav"><button onclick="back()">◀</button><button onclick="home()">🏠</button><button onclick="forward()">▶</button></nav>`}`}
function loginView(){return `<header class="header"><img class="logo" src="assets/logo-aitue.png"><div><h1>CheckObra</h1><p>Castellón 227</p></div></header><main class="screen"><img class="hero" src="assets/castellon227.png"><h2>Ingreso</h2><p class="intro">Checklist, biblioteca técnica y control de avance de obra.</p><select id="loginUser">${users.map(x=>`<option value="${x.id}">${x.name} · ${x.role}</option>`).join('')}</select><input id="loginPass" type="password" placeholder="Clave de acceso"><button class="primary" onclick="login()">Entrar</button></main>`}
function homeView(){const user=u();if(user.profile==='supervisor')return supervisorHome(user);if(user.profile==='calidad')return calidadHome();if(user.profile==='gonzalo')return gonzaloHome();if(user.profile==='admin')return adminHome();if(user.profile==='oficina')return oficinaHome();return terrenoHome();}
function supervisorHome(user){return appShell(`<h2>Inicio · ${user.name}</h2><div class="kpi" onclick="go('observaciones')"><span>Observaciones por atender</span><b>${observationsForUser(user).length}</b></div><div class="kpi" onclick="go('programa')"><span>Compromisos pendientes</span><b>${pendingProgramFor(user).length}</b></div><div class="kpi" onclick="go('papas')"><span>Papas activas</span><b>${papasFor(user).length}</b></div><div class="grid"><button class="card" onclick="go('misPartidas')">🏗 Mis partidas</button><button class="card" onclick="go('edificio')">🏢 Estado edificio</button><button class="card" onclick="go('programa')">📅 Mis compromisos</button><button class="card" onclick="go('papas')">🥔 Papas</button><button class="card" onclick="go('biblioteca')">📚 Biblioteca</button><button class="card" onclick="go('documentos')">📂 Documentos</button><button class="card" onclick="go('notas')">📝 Mis notas</button></div>`)}
function calidadHome(){return appShell(`<h2>Inicio · Vicente Bizama</h2><div class="kpi" onclick="go('centroCalidad')"><span>Avisos pendientes</span><b>${state.data.qualityNotes.filter(n=>n.status!=='Cerrada').length}</b></div><div class="kpi" onclick="go('observaciones')"><span>Observaciones abiertas</span><b>${state.data.observations.filter(o=>o.status!=='Cerrada').length}</b></div><div class="kpi" onclick="go('centroCalidad')"><span>Listas para validar</span><b>${state.data.qualityNotes.filter(n=>n.status==='Pendiente validación').length}</b></div><div class="grid"><button class="card" onclick="go('centroCalidad')">✅ Centro Calidad</button><button class="card" onclick="go('edificio')">🏢 Auditar edificio</button><button class="card" onclick="go('observaciones')">🔴 Observaciones</button><button class="card" onclick="go('historial')">📋 Historial Calidad</button><button class="card" onclick="go('papas')">🥔 Papas</button><button class="card" onclick="go('biblioteca')">📚 Biblioteca</button><button class="card" onclick="go('documentos')">📂 Documentos</button></div>`)}
function gonzaloHome(){const sup=users.filter(x=>x.profile==='supervisor');return appShell(`<h2>Inicio · Gonzalo Riquelme</h2><div class="kpi"><span>Cumplimiento semanal</span><b>${weeklyPct()}%</b></div><div class="kpi" onclick="go('atrasos')"><span>Atrasos según programa</span><b>${latePrograms().length}</b></div><div class="kpi" onclick="go('observaciones')"><span>Observaciones abiertas</span><b>${state.data.observations.filter(o=>o.status!=='Cerrada').length}</b></div><div class="kpi" onclick="go('papas')"><span>Papas activas</span><b>${state.data.papas.filter(p=>p.status!=='Cerrada').length}</b></div><h3>Supervisores</h3>${sup.map(s=>`<div class="partRow" onclick="go('supervisorDetalle','${s.id}')"><b>${s.name}</b><span class="tag ${programPct(s.id)>85?'ok':programPct(s.id)>70?'warn':'bad'}">${programPct(s.id)}%</span></div>`).join('')}<div class="grid"><button class="card" onclick="go('prioridades')">🎯 Prioridades</button><button class="card" onclick="go('programa')">📅 Programa semanal</button><button class="card" onclick="go('centroCalidad')">✅ Calidad</button><button class="card" onclick="go('edificio')">🏢 Estado edificio</button><button class="card" onclick="go('papas')">🥔 Papas</button><button class="card" onclick="go('biblioteca')">📚 Biblioteca</button><button class="card" onclick="go('documentos')">📂 Documentos</button></div>`)}
function adminHome(){return appShell(`<h2>Dashboard Ejecutivo · Cristóbal</h2>${dashboardKpis()}<h3>Centro de Gestión</h3>${graphBlock('Programado vs Ejecutado', supervisorBars())}${graphBlock('Avance por piso', floorBars())}${graphBlock('Ejecutado vs Validado', executedValidatedBars())}<div class="grid"><button class="card" onclick="go('centroGestion')">🎯 Centro Gestión</button><button class="card" onclick="go('programa')">📅 Programa semanal</button><button class="card" onclick="go('edificio')">🏢 Estado Obra</button><button class="card" onclick="go('restricciones')">🚧 Restricciones</button><button class="card" onclick="go('papas')">🥔 Papas</button><button class="card" onclick="go('observaciones')">🔴 Observaciones</button><button class="card" onclick="go('reportes')">📊 Reportes</button><button class="card" onclick="go('biblioteca')">📚 Biblioteca</button><button class="card" onclick="go('documentos')">📂 Documentos</button></div>`)}
function terrenoHome(){return appShell(`<h2>Inicio · Paul González</h2>${dashboardKpis(true)}<div class="kpi"><span>Frentes disponibles</span><b>${availableFronts()}</b></div><div class="grid"><button class="card" onclick="go('edificio')">🏗 Estado Obra</button><button class="card" onclick="go('programa')">📅 Programa semanal</button><button class="card" onclick="go('restricciones')">🚧 Restricciones</button><button class="card" onclick="go('observaciones')">🔴 Observaciones</button><button class="card" onclick="go('papas')">🥔 Papas</button><button class="card" onclick="go('centroCalidad')">✅ Calidad</button><button class="card" onclick="go('biblioteca')">📚 Biblioteca</button><button class="card" onclick="go('documentos')">📂 Documentos</button><button class="card" onclick="go('reportes')">📊 Reportes</button></div>`)}
function oficinaHome(){return appShell(`<h2>Inicio · Constanza Reyes</h2><div class="kpi"><span>Documentos vigentes</span><b>${state.data.documents.filter(d=>d.status==='Vigente').length}</b></div><div class="kpi"><span>RDI pendientes</span><b>${state.data.documents.filter(d=>d.type==='RDI'&&d.status!=='Cerrada').length}</b></div><div class="kpi"><span>Comunicados técnicos</span><b>${state.data.techNotices.length}</b></div><div class="grid"><button class="card" onclick="go('documentos')">📂 Documentos</button><button class="card" onclick="go('documentos','Plano')">📄 Planos</button><button class="card" onclick="go('documentos','Protocolo')">📋 Protocolos</button><button class="card" onclick="go('documentos','RDI')">📌 RDI / Consultas</button><button class="card" onclick="go('documentos','Ficha Técnica')">📚 Fichas técnicas</button><button class="card" onclick="go('comunicadosTecnicos')">📢 Comunicados técnicos</button><button class="card" onclick="go('biblioteca')">📚 Biblioteca</button><button class="card" onclick="go('reportes')">📊 Reportes</button></div>`)}
function dashboardKpis(){return `<div class="two"><div class="kpi"><span>Avance validado</span><b>${validatedPct()}%</b></div><div class="kpi"><span>Cumplimiento semanal</span><b>${weeklyPct()}%</b></div><div class="kpi"><span>Obs. abiertas</span><b>${state.data.observations.filter(o=>o.status!=='Cerrada').length}</b></div><div class="kpi"><span>Restricciones</span><b>${state.data.restrictions.filter(r=>r.status!=='Cerrada').length}</b></div></div>`}
function graphBlock(title,rows){return `<div class="item"><b>${title}</b>${rows}</div>`}
function bar(label,pct){return `<div><div class="partRow"><span>${label}</span><b>${pct}%</b></div><div class="bar"><span style="width:${pct}%"></span></div></div>`}
function supervisorBars(){return users.filter(x=>x.profile==='supervisor').map(s=>bar(s.name,programPct(s.id))).join('')}
function floorBars(){let h='';for(let f=2;f<=17;f++)h+=bar('Piso '+f,floorProgress(f,allParts));return h}
function executedValidatedBars(){return bar('Ejecutado',executedPct())+bar('Validado Calidad',validatedPct())}
function weeklyPct(){const p=state.data.program.filter(x=>x.status!=='Cancelado');if(!p.length)return 0;return Math.round(p.filter(x=>x.status==='Cumplido').length/p.length*100)}
function programPct(id){const p=state.data.program.filter(x=>x.resp===id&&x.status!=='Cancelado');if(!p.length)return 0;return Math.round(p.filter(x=>x.status==='Cumplido').length/p.length*100)}
function latePrograms(){return state.data.program.filter(p=>p.status==='Atrasado')}
function allStateEntries(){return Object.values(state.data.states)}
function validatedPct(){const e=allStateEntries();if(!e.length)return 0;return Math.round(e.filter(x=>x.status==='Validada Calidad').length/e.length*100)}
function executedPct(){const e=allStateEntries();if(!e.length)return 0;return Math.round(e.filter(x=>['Ejecutada','Validada Calidad'].includes(x.status)).length/e.length*100)}
function availableFronts(){let n=0;for(let f=2;f<=17;f++){let max=f===2?5:6;for(let c=1;c<=max;c++){if(deptProgressFor(f*100+c,allParts).pct<100)n++}}return n}
function misPartidas(){const user=u();return appShell(`<h2>Mis partidas</h2>${user.works.map(p=>`<button class="item" style="width:100%;text-align:left" onclick="go('edificio','${p}')"><b>${p}</b><br><span class="muted">Checklist, biblioteca y avance asociado</span></button>`).join('')}`)}
function edificio(){const selectedPart=state.param;const user=u();let parts=(selectedPart? [selectedPart] : (user.profile==='supervisor'?user.works:allParts));let title=user.profile==='supervisor'&&!selectedPart?'Estado edificio · mis partidas': selectedPart?`Estado edificio · ${selectedPart}`:'Auditar edificio';let h=`<h2>${title}</h2><p class="intro">Estado visual por piso y departamento.</p><div class="legend"><span><i class="dot gray"></i> Sin iniciar</span><span><i class="dot yellow"></i> En ejecución</span><span><i class="dot blue"></i> Ejecutada</span><span><i class="dot green"></i> Validada</span><span><i class="dot red"></i> Observada</span></div>`;for(let f=2;f<=17;f++){let max=f===2?5:6;h+=`<details class="floor" ${f<=4?'open':''}><summary>Piso ${f} · Avance ${floorProgress(f,parts)}%</summary><div class="floorGrid">`;for(let c=1;c<=max;c++){let d=f*100+c, st=deptProgressFor(d,parts);h+=`<button class="deptBtn state-${st.cls}" onclick="go('depto',{dept:${d},part:${selectedPart?`'${selectedPart}'`:'null'}})">${d}</button>`}h+=`</div></details>`}return appShell(h)}
function depto(){const {dept,part}=state.param||{};const meta=deptMeta(dept);const user=u();let parts=part?[part]:(user.profile==='supervisor'?user.works:allParts);let st=deptProgressFor(dept,parts);let h=`<h2>Depto ${dept}</h2><p class="intro">Piso ${meta.floor} · Tipo ${meta.type} · ${meta.area}</p><div class="kpi"><span>Estado departamento</span><b>${st.txt}</b></div>`;
if(part){h+=`<h3>${part}</h3>`;let targets=partApplies(part,meta.rooms);targets.forEach(r=>{const s=getState(dept,part,r);h+=`<div class="partRow"><span>${r==='DEPTO'?'Control por departamento':r}<br><small class="mini">${s.status}</small></span><button onclick="go('revision',{dept:${dept},part:'${part}',room:'${r}'})">Abrir checklist</button></div>`});}
else{h+=`<h3>${user.profile==='calidad'||user.profile==='admin'||user.profile==='terreno'||user.profile==='gonzalo'?'Todas las partidas del departamento':'Estado de mis partidas'}</h3>`;parts.forEach(p=>{let targets=partApplies(p,meta.rooms), vals=targets.map(r=>getState(dept,p,r).status);let status=vals.includes('Observada')?'Observada':vals.every(x=>x==='Validada Calidad')?'Validada Calidad':vals.includes('Ejecutada')?'Ejecutada':vals.includes('En ejecución')?'En ejecución':'Sin iniciar';h+=`<div class="partRow"><span><b>${p}</b><br><small>${targets.length>1?targets.length+' controles':(targets[0]==='DEPTO'?'Control por departamento':targets[0])}</small></span><span class="tag ${status==='Validada Calidad'?'ok':status==='Observada'?'bad':status==='Ejecutada'?'blue':status==='En ejecución'?'warn':''}">${status}</span><button onclick="go('depto',{dept:${dept},part:'${p}'})">Ver</button></div>`})}
return appShell(h)}
function revision(){const {dept,part,room}=state.param;const s=getState(dept,part,room);const user=u();const isQuality=user.id==='vicente';const missing=depsMissing(dept,part);const blocked=missing.length&&!canOverrideBlock();let blocker=missing.length?`<div class="item hot"><b>🔒 Partida bloqueada por dependencias constructivas</b><br>Pendientes: ${missing.map(x=>`<span class="tag bad">${x}</span>`).join(' ')}<br><small>Solo Gonzalo, Paul, Vicente o Cristóbal pueden liberar excepcionalmente.</small></div>`:'';let saveBtn=blocked?`<button class="danger" onclick="alert('No se puede guardar avance hasta liberar dependencias.')">Bloqueado</button>`:`<button class="primary" onclick="saveReview()">Guardar</button>`;let h=`<h2>${part}</h2><p class="intro">Depto ${dept} · ${room==='DEPTO'?'':room}</p>${blocker}<div class="kpi"><span>Estado actual</span><b>${s.status}</b></div><h3>Checklist</h3><div class="checklistBox">${(checklist[part]||[]).map((x,i)=>`<label class="item"><input type="checkbox" id="ck${i}"><span>${x}</span></label>`).join('')}</div><h3>Actualizar estado</h3><select id="revState">${stateOrder.filter(x=>isQuality||!['Validada Calidad','Observada'].includes(x)).map(x=>`<option ${x===s.status?'selected':''}>${x}</option>`).join('')}</select><label class="rangeLabel">Avance declarado: <b id="revAvLabel">${s.avance||0}%</b></label><input id="revAv" type="range" min="0" max="100" step="25" value="${s.avance||0}" oninput="updateRangeLabel()"><textarea id="revObs" placeholder="Comentario, observación o respaldo">${s.obs||''}</textarea>${saveBtn}`;
if(isQuality)h+=`<h3>Acciones Calidad</h3><div class="two"><button class="btn" onclick="qualityApprove()">Validar Calidad</button><button class="danger" onclick="qualityObserve()">Observar</button></div>`;return appShell(h)}
function updateRangeLabel(){const e=document.getElementById('revAvLabel');if(e)e.innerText=(document.getElementById('revAv')?.value||0)+'%'}
function saveReview(){const {dept,part,room}=state.param;setPartStatus(dept,part,room,document.getElementById('revState').value,document.getElementById('revAv').value,document.getElementById('revObs').value);alert('Revisión guardada');go('depto',{dept,part:null})}
function qualityApprove(){const {dept,part,room}=state.param;setPartStatus(dept,part,room,'Validada Calidad',100,'Validado por Calidad');state.data.qualityNotes=state.data.qualityNotes.map(n=>n.dept==dept&&n.part===part&&n.room===room?{...n,status:'Cerrada'}:n);save();alert('Avance validado por Calidad');go('centroCalidad')}
function qualityObserve(){const {dept,part,room}=state.param;const detail=prompt('Detalle de observación');if(!detail)return;setPartStatus(dept,part,room,'Observada',0,detail);let resp=responsibleFor(part);state.data.observations.unshift({id:Date.now(),by:u().id,byName:u().name,resp,dept,part,room,severity:'Crítica',text:detail,status:'Abierta',date:new Date().toLocaleString()});save();alert('Observación creada');go('centroCalidad')}
function responsibleFor(part){return users.find(x=>x.profile==='supervisor'&&x.works.includes(part))?.id||'nicole'}
function programa(){const user=u();if(!canManage())return appShell(`<h2>Mis compromisos</h2><div class="tabs"><button class="active">Pendientes</button><button onclick="go('programaHist')">Historial</button></div>${programList(state.data.program.filter(p=>p.resp===user.id&&!['Cumplido','Cancelado'].includes(p.status)))}`);return appShell(`<h2>Programa semanal</h2><div class="item"><select id="progPart">${allParts.map(p=>`<option>${p}</option>`)}</select><select id="progResp">${users.filter(x=>x.profile==='supervisor').map(s=>`<option value="${s.id}">${s.name}</option>`)}</select><input id="progFloor" type="number" placeholder="Piso, ejemplo 4"><input id="progRange" placeholder="Deptos, ejemplo 401-404 o 401,402"><select id="progDay">${['Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'].map(d=>`<option>${d}</option>`)}</select><textarea id="progNote" placeholder="Observación / meta"></textarea><button class="primary" onclick="addProgram()">Agregar compromiso</button></div><h3>Filtrar por supervisor</h3><select id="progFilter" onchange="render()"><option value="todos">Todos</option>${users.filter(x=>x.profile==='supervisor').map(s=>`<option value="${s.id}">${s.name}</option>`)}</select>${programList(filteredPrograms())}`)}
function filteredPrograms(){let f=document.getElementById('progFilter')?.value||'todos';return f==='todos'?state.data.program:state.data.program.filter(p=>p.resp===f)}
function programList(list){return list.length?list.map(p=>`<div class="item"><b>${p.day} · ${p.part}</b><br>Piso ${p.floor} · Deptos ${p.range}<br>Responsable: ${users.find(u=>u.id===p.resp)?.name}<br><span class="tag ${p.status==='Cumplido'?'ok':p.status==='Atrasado'?'bad':p.status==='Restringido'?'warn':'blue'}">${p.status}</span><div class="bar"><span style="width:${p.avance||0}%"></span></div><small>${p.note||''}</small><div class="two">${u().id===p.resp?`<button class="btn" onclick="acceptProgram(${p.id})">Aceptar / avance</button><button class="secondary" onclick="restrictProgram(${p.id})">Informar restricción</button>`:''}${canManage()?`<button class="btn" onclick="markProgram(${p.id},'Cumplido')">Cumplido</button><button class="danger" onclick="markProgram(${p.id},'Atrasado')">Atrasado</button>`:''}</div></div>`).join(''):'<p class="intro">Sin compromisos.</p>'}
function addProgram(){state.data.program.unshift({id:Date.now(),part:v('progPart'),resp:v('progResp'),floor:v('progFloor'),range:v('progRange'),day:v('progDay'),note:v('progNote'),status:'Pendiente aceptación',avance:0,date:new Date().toLocaleString(),by:u().id});save();render()}
function acceptProgram(id){let av=prompt('Avance del compromiso (%)','0');state.data.program=state.data.program.map(p=>p.id===id?{...p,status:Number(av)>=100?'Cumplido':'En ejecución',avance:Number(av)}:p);save();render()}
function restrictProgram(id){let reason=prompt('Motivo restricción: material, plano, especialidad previa, mano de obra, suministro u otro');if(!reason)return;state.data.program=state.data.program.map(p=>p.id===id?{...p,status:'Restringido',restriction:reason}:p);state.data.restrictions.unshift({id:Date.now(),source:'programa',programId:id,reason,status:'Abierta',by:u().id,date:new Date().toLocaleString()});save();render()}
function markProgram(id,status){state.data.program=state.data.program.map(p=>p.id===id?{...p,status,avance:status==='Cumplido'?100:p.avance}:p);save();render()}
function programaHist(){return appShell(`<h2>Historial compromisos</h2>${programList(state.data.program.filter(p=>p.resp===u().id&&['Cumplido','Cancelado'].includes(p.status)))}`)}
function papas(){let list=papasFor(u());if(canPapa())list=state.data.papas;return appShell(`<h2>Papas frías, tibias y calientes</h2>${canPapa()?`<div class="item"><select id="papaTo"><option value="todos">Todos</option>${users.filter(x=>x.profile==='supervisor').map(s=>`<option value="${s.id}">${s.name}</option>`)}</select><select id="papaUrg"><option>Caliente</option><option>Tibia</option><option>Fría</option></select><input id="papaTitle" placeholder="Título"><textarea id="papaBody" placeholder="Solicitud"></textarea><button class="primary" onclick="addPapa()">Crear papa</button></div>`:''}${['Caliente','Tibia','Fría'].map(t=>`<h3>${t==='Caliente'?'🔴':t==='Tibia'?'🟡':'🟢'} Papas ${t}s</h3>${papaList(list.filter(p=>p.urgency===t))}`).join('')}`)}
function papaList(list){return list.length?list.map(p=>`<div class="item ${p.urgency==='Caliente'?'hot':p.urgency==='Tibia'?'warm':'cold'}"><b>${p.title}</b><br>${p.body}<br><small>Solicita: ${users.find(x=>x.id===p.by)?.name||p.by} · Para: ${p.to==='todos'?'Todos':users.find(x=>x.id===p.to)?.name}</small><br><span class="tag">${p.status}</span>${p.status!=='Cerrada'?`<button class="secondary" onclick="closePapa(${p.id})">Marcar atendida</button>`:''}</div>`).join(''):'<p class="intro">Sin papas.</p>'}
function addPapa(){state.data.papas.unshift({id:Date.now(),to:v('papaTo'),urgency:v('papaUrg'),title:v('papaTitle'),body:v('papaBody'),by:u().id,status:'Pendiente',date:new Date().toLocaleString()});save();render()}
function closePapa(id){state.data.papas=state.data.papas.map(p=>p.id===id?{...p,status:'Cerrada'}:p);save();render()}
function observaciones(){let list=u().profile==='supervisor'?observationsForUser(u()):state.data.observations.filter(o=>o.status!=='Cerrada');return appShell(`<h2>Observaciones</h2>${list.map(o=>`<div class="item hot"><b>${o.part} · Depto ${o.dept}</b><br>${o.room==='DEPTO'?'Control por departamento':o.room}<br>${o.text}<br><small>Observó: ${users.find(x=>x.id===o.by)?.name||o.by} · Resp: ${users.find(x=>x.id===o.resp)?.name}</small><br><span class="tag bad">${o.severity}</span><span class="tag">${o.status}</span>${o.resp===u().id?`<button class="secondary" onclick="obsProcess(${o.id})">Marcar en proceso</button>`:''}${u().id==='vicente'?`<button class="btn" onclick="closeObs(${o.id})">Cerrar</button>`:''}</div>`).join('')||'<p class="intro">Sin observaciones abiertas.</p>'}`)}
function obsProcess(id){state.data.observations=state.data.observations.map(o=>o.id===id?{...o,status:'En proceso'}:o);save();render()}
function closeObs(id){state.data.observations=state.data.observations.map(o=>o.id===id?{...o,status:'Cerrada'}:o);save();render()}
function centroCalidad(){const notes=state.data.qualityNotes.filter(n=>n.status!=='Cerrada');return appShell(`<h2>Centro Calidad</h2><h3>Pendientes de validación</h3>${notes.map(n=>`<div class="item info"><b>${n.part} · Depto ${n.dept}</b><br>${n.room==='DEPTO'?'Control por departamento':n.room}<br>Informa: ${n.from}<br><span class="tag blue">${n.status}</span><button class="btn" onclick="go('revision',{dept:${n.dept},part:'${n.part}',room:'${n.room}'})">Revisar</button></div>`).join('')||'<p class="intro">Sin pendientes de calidad.</p>'}`)}
function biblioteca(){let q=(document.getElementById('libQ')?.value||'').toLowerCase();let entries=Object.entries(library).filter(([k,d])=>(k+' '+d.doc+' '+d.inst.join(' ')+' '+d.tol.join(' ')+' '+d.fullTol.join(' ')+' '+d.method.join(' ')+' '+d.err.join(' ')+' '+d.tip).toLowerCase().includes(q));return appShell(`<h2>Biblioteca del Saber</h2><input id="libQ" placeholder="Buscar partida o tolerancia..." oninput="render()" value="${q}"><div class="tip">💡 <b>¿Sabías que?</b><br>${tips[Math.floor(Math.random()*tips.length)]}</div><button class="secondary" onclick="render()" style="width:100%">Nuevo tip aleatorio</button><div class="lib">${entries.map(([k,d])=>`<details><summary>${k}</summary><div class="item"><b>📏 Instrumentos</b><ul>${d.inst.map(x=>`<li>${x}</li>`).join('')}</ul></div><div class="item"><b>📐 Tolerancias clave</b><ul>${d.tol.map(x=>`<li>${x}</li>`).join('')}</ul><details class="subdetails"><summary>Ver tolerancias completas</summary><ul>${d.fullTol.map(x=>`<li>${x}</li>`).join('')}</ul></details></div><div class="item"><b>🔍 Cómo revisar</b><ol>${d.method.map(x=>`<li>${x}</li>`).join('')}</ol></div><div class="item"><b>⚠️ Errores frecuentes</b><ul>${d.err.map(x=>`<li>${x}</li>`).join('')}</ul></div><div class="tip"><b>💡 Sabías que...</b><br>${d.tip}</div></details>`).join('')}</div>`)}
function notas(){let list=state.data.notes.filter(n=>n.user===u().id);return appShell(`<h2>Mis notas</h2><div class="item"><textarea id="noteBody" placeholder="Nueva nota personal..."></textarea><button class="primary" onclick="addNote()">Agregar nota</button></div>${list.map(n=>`<div class="item"><label><input type="checkbox" ${n.done?'checked':''} onchange="toggleNote(${n.id})"> ${n.body}</label><br><small>${n.date}</small><button class="danger" onclick="deleteNote(${n.id})">Eliminar</button></div>`).join('')||'<p class="intro">Sin notas personales.</p>'}`)}
function addNote(){if(!v('noteBody'))return;state.data.notes.unshift({id:Date.now(),user:u().id,body:v('noteBody'),done:false,date:new Date().toLocaleString()});save();render()}
function toggleNote(id){state.data.notes=state.data.notes.map(n=>n.id===id?{...n,done:!n.done}:n);save();render()}
function deleteNote(id){state.data.notes=state.data.notes.filter(n=>n.id!==id);save();render()}

function documentos(){const filter=state.param;const docs=state.data.documents.filter(d=>!filter||d.type===filter);const canAdd=['paul','cristobal','constanza','gonzalo','vicente'].includes(u().id);const canDelete=['paul','cristobal','constanza'].includes(u().id);return appShell(`<h2>${filter||'Documentos'}</h2>${canAdd?`<div class="item"><select id="docType"><option>Plano</option><option>Protocolo</option><option>RDI</option><option>Ficha Técnica</option><option>Procedimiento</option><option>Certificado</option><option>Acta</option><option>Informe</option><option>Fotografía</option></select><input id="docTitle" placeholder="Nombre del documento"><input id="docFile" type="file"><input id="docRef" placeholder="Link, código o referencia"><select id="docStatus"><option>Vigente</option><option>Reemplazado</option><option>Obsoleto</option><option>Pendiente</option><option>Cerrada</option></select><button class="primary" onclick="addDocument()">Subir documento</button></div>`:''}${docs.map(d=>`<div class="item"><b>${d.title}</b><br><span class="tag blue">${d.type}</span><span class="tag ${d.status==='Vigente'?'ok':d.status==='Obsoleto'?'bad':'warn'}">${d.status}</span><br><small>${d.ref||''}</small>${d.fileData?`<br><a class="docLink" href="${d.fileData}" target="_blank">Abrir archivo</a>`:''}<br><small>Subido por ${d.by} · ${d.date}</small>${canDelete?`<br><button class="danger" onclick="deleteDocument(${d.id})">Eliminar</button>`:''}</div>`).join('')||'<p class="intro">Sin documentos registrados.</p>'}`)}
function addDocument(){if(!v('docTitle'))return;const file=document.getElementById('docFile')?.files?.[0];const base={id:Date.now(),type:v('docType'),title:v('docTitle'),ref:v('docRef')||(file?file.name:''),status:v('docStatus'),by:u().name,date:new Date().toLocaleString()};if(file){const reader=new FileReader();reader.onload=()=>{state.data.documents.unshift({...base,fileName:file.name,fileData:reader.result});save();render()};reader.readAsDataURL(file);return;}state.data.documents.unshift(base);save();render()}
function deleteDocument(id){state.data.documents=state.data.documents.filter(d=>d.id!==id);save();render()}
function comunicadosTecnicos(){return appShell(`<h2>Comunicados técnicos</h2><div class="item"><input id="noticeTitle" placeholder="Título comunicado"><textarea id="noticeBody" placeholder="Información importante para terreno"></textarea><button class="primary" onclick="addTechNotice()">Publicar comunicado</button></div>${state.data.techNotices.map(n=>`<div class="item info"><b>${n.title}</b><br>${n.body}<br><small>${n.by} · ${n.date}</small></div>`).join('')||'<p class="intro">Sin comunicados técnicos.</p>'}`)}
function addTechNotice(){if(!v('noticeTitle'))return;state.data.techNotices.unshift({id:Date.now(),title:v('noticeTitle'),body:v('noticeBody'),by:u().name,date:new Date().toLocaleString()});save();render()}
function prioridades(){return centroGestion('Prioridades')}
function centroGestion(title='Centro Gestión'){return appShell(`<h2>${title}</h2><div class="item hot"><b>Atrasos</b><br>${latePrograms().length} compromisos atrasados.</div><div class="item hot"><b>Observaciones críticas</b><br>${state.data.observations.filter(o=>o.status!=='Cerrada'&&o.severity==='Crítica').length} abiertas.</div><div class="item warm"><b>Restricciones</b><br>${state.data.restrictions.filter(r=>r.status!=='Cerrada').length} activas.</div><div class="item hot"><b>Papas calientes</b><br>${state.data.papas.filter(p=>p.status!=='Cerrada'&&p.urgency==='Caliente').length} sin atender.</div><div class="item info"><b>Pendientes de calidad</b><br>${state.data.qualityNotes.filter(n=>n.status!=='Cerrada').length} listas para validar.</div>`)}
function atrasos(){return appShell(`<h2>Atrasos según programa</h2>${programList(latePrograms())}`)}
function restricciones(){return appShell(`<h2>Restricciones</h2>${state.data.restrictions.map(r=>`<div class="item warm"><b>${r.reason}</b><br>${r.status}<br><small>${r.date}</small><button class="secondary" onclick="closeRestriction(${r.id})">Cerrar</button></div>`).join('')||'<p class="intro">Sin restricciones activas.</p>'}`)}
function closeRestriction(id){state.data.restrictions=state.data.restrictions.map(r=>r.id===id?{...r,status:'Cerrada'}:r);save();render()}
function historial(){return appShell(`<h2>Historial</h2>${state.data.history.map(h=>`<div class="item"><b>${h.text}</b><br><small>${h.date}</small></div>`).join('')||'<p class="intro">Sin historial.</p>'}`)}
function reportes(){return appShell(`<h2>Reportes</h2><div class="item"><b>Calidad primera pasada</b><br>${firstPass()}%</div><div class="item"><b>Edad observaciones</b><br>0-3 días: ${state.data.observations.filter(o=>o.status!=='Cerrada').length}<br>4-7 días: 0<br>+7 días: 0</div><div class="item"><b>Top partidas problemáticas</b><br>${topObserved()}</div>`)}
function produccion(){return appShell(`<h2>Producción</h2>${graphBlock('Producción por supervisor', supervisorBars())}${graphBlock('Producción por piso', floorBars())}`)}
function firstPass(){const obs=state.data.observations.length, val=allStateEntries().filter(x=>x.status==='Validada Calidad').length;return val+obs?Math.round(val/(val+obs)*100):100}
function topObserved(){const m={};state.data.observations.forEach(o=>m[o.part]=(m[o.part]||0)+1);return Object.entries(m).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([k,v])=>`${k}: ${v}`).join('<br>')||'Sin datos'}
function supervisorDetalle(id){const s=users.find(x=>x.id===id);return appShell(`<h2>${s.name}</h2><div class="kpi"><span>Cumplimiento</span><b>${programPct(id)}%</b></div><div class="kpi"><span>Compromisos pendientes</span><b>${pendingProgramFor(s).length}</b></div><div class="kpi"><span>Obs. abiertas</span><b>${observationsForUser(s).length}</b></div><div class="kpi"><span>Papas</span><b>${papasFor(s).length}</b></div>`)}
function seed(){if(localStorage.getItem('checkobra_v11_base_real_seed'))return;state.data={states:{},observations:[],program:[],papas:[],notes:[],history:[],qualityNotes:[],restrictions:[],documents:[],techNotices:[]};localStorage.setItem('checkobra_v11_base_real_seed','1');save()}
function login(){const selected=users.find(x=>x.id===v('loginUser'));const passOk=selected&&(state.testMode||selected.pass===v('loginPass'));if(!passOk){alert('Clave incorrecta');return}state.currentUser=selected.id;state.route='home';save();render()}
function logout(){state.currentUser=null;state.route='login';save();render()}
function v(id){return document.getElementById(id)?.value||''}
function render(){const app=document.getElementById('app');if(!state.currentUser||state.route==='login'){app.innerHTML=loginView();return}const routes={home:homeView,misPartidas,edificio,depto,revision,programa,programaHist,papas,observaciones,centroCalidad,biblioteca,notas,prioridades,centroGestion,restricciones,historial,reportes,produccion,atrasos,supervisorDetalle,documentos,comunicadosTecnicos};app.innerHTML=(routes[state.route]||homeView)(state.param)}
window.login=login;window.logout=logout;window.toggleTestMode=toggleTestMode;window.quickSwitchUser=quickSwitchUser;window.go=go;window.back=back;window.forward=forward;window.home=home;window.saveReview=saveReview;window.qualityApprove=qualityApprove;window.qualityObserve=qualityObserve;window.addProgram=addProgram;window.acceptProgram=acceptProgram;window.restrictProgram=restrictProgram;window.markProgram=markProgram;window.addPapa=addPapa;window.closePapa=closePapa;window.obsProcess=obsProcess;window.closeObs=closeObs;window.addNote=addNote;window.toggleNote=toggleNote;window.deleteNote=deleteNote;window.closeRestriction=closeRestriction;window.addDocument=addDocument;window.addTechNotice=addTechNotice;window.render=render;window.updateRangeLabel=updateRangeLabel;window.secretTap=secretTap;window.deleteDocument=deleteDocument;


let secretTapCount=0, secretTapTimer=null;
function secretTap(){if(!state.currentUser||state.currentUser!=='paul')return;secretTapCount++;clearTimeout(secretTapTimer);secretTapTimer=setTimeout(()=>secretTapCount=0,1200);if(secretTapCount>=5){state.secretOpen=!state.secretOpen;secretTapCount=0;save();render();}}
function toggleTestMode(){state.testMode=!state.testMode;save();render()}
function quickSwitchUser(){const id=v('quickUser');if(!id)return;state.currentUser=id;state.route='home';save();render()}
load();seed();listenCloud();render();
